   328|// ═══════════════════════════════════════════════════════════════════
   329|// SNAP HANDLER — uses ROUTE-BASED navigation (not query params)
   330|// ═══════════════════════════════════════════════════════════════════
   331|const app = new Hono();
   332|
   333|const snap: SnapFunction = async (ctx) => {
   334|  const base = snapBase(ctx.request);
   335|
   336|  // GET: always show gate
   337|  if (ctx.action.type === "get") {
   338|    return gatePage(base);
   339|  }
   340|
   341|  // POST: determine action from the registered route path
   342|  const fid = ctx.action.user.fid;
   343|  const path = new URL(ctx.request.url).pathname;
   344|
   345|  // Route: /gate-pass or /gate-yass
   346|  if (path === "/gate-pass") {
   347|    await setBehavioralTag(fid, "cautious");
   348|    return thanksPage();
   349|  }
   350|  if (path === "/gate-yass") {
   351|    await setBehavioralTag(fid, "adventurous");
   352|    return await handleGate(fid, base);
   353|  }
   354|
   355|  // Route: /swipe-pass?tid=X or /swipe-yass?tid=X
   356|  if (path.startsWith("/swipe-pass")) {
   357|    const tid = new URL(ctx.request.url).searchParams.get("tid");
   358|    if (tid) return await handleSwipe(fid, parseInt(tid), "pass", base);
   359|  }
   360|  if (path.startsWith("/swipe-yass")) {
   361|    const tid = new URL(ctx.request.url).searchParams.get("tid");
   362|    if (tid) return await handleSwipe(fid, parseInt(tid), "yass", base);
   363|  }
   364|
   365|  return gatePage(base);
   366|};
   367|
   368|// ─── Gate Handler ─────────────────────────────────────────────────
   369|async function handleGate(fid: number, base: string) {
   370|  const existing = await getQualification(fid);
   371|  if (existing?.qualified) return await showNext(fid, base);
   372|
   373|  const users = await fetchUsers([fid]);
   374|  if (!users.length) return rejectionPage();
   375|
   376|  const qual = qualifyUser(users[0]);
   377|  await setQualification(fid, qual);
   378|  if (!qual.qualified) return rejectionPage();
   379|
   380|  return await showNext(fid, base);
   381|}
   382|
   383|// ─── Swipe Handler ────────────────────────────────────────────────
   384|async function handleSwipe(swiperFid: number, targetFid: number, direction: string, base: string) {
   385|  const count = await getSwipeCount(swiperFid);
   386|  if (count >= DAILY_SWIPE_LIMIT) return dailyLimitPage();
   387|
   388|  const tag = (await getBehavioralTag(swiperFid)) ?? "unknown";
   389|  await recordSwipe(swiperFid, targetFid, direction, tag);
   390|  await incrementSwipe(swiperFid);
   391|
   392|  return await showNext(swiperFid, base);
   393|}
   394|
   395|// ─── Show Next Profile ────────────────────────────────────────────
   396|async function showNext(fid: number, base: string) {
   397|  const count = await getSwipeCount(fid);
   398|  if (count >= DAILY_SWIPE_LIMIT) return dailyLimitPage();
   399|
   400|  let pool = await getProfilePool(fid);
   401|  const swiped = await getSwipedFids(fid);
   402|  pool = pool.filter(p => !swiped.has(p.fid));
   403|
   404|  if (pool.length < 3) {
   405|    const newP = await buildProfilePool(fid);
   406|    const existing = new Set(pool.map(p => p.fid));
   407|    for (const p of newP) {
   408|      if (!existing.has(p.fid) && !swiped.has(p.fid)) {
   409|        pool.push(p);
   410|        existing.add(p.fid);
   411|      }
   412|    }
   413|    await setProfilePool(fid, pool);
   414|  }
   415|
   416|  if (pool.length === 0) return noMorePage();
   417|
   418|  const next = pool[0];
   419|  await setProfilePool(fid, pool.slice(1));
   420|  return profilePage(next, DAILY_SWIPE_LIMIT - count, base, pool.length - 1);
   421|}
