   423|// ═══════════════════════════════════════════════════════════════════
   424|// SNAP UI PAGES
   425|// ═══════════════════════════════════════════════════════════════════
   426|const ACCENT = "purple" as const;
   427|
   428|function gatePage(base: string) {
   429|  return {
   430|    version: SPEC,
   431|    theme: { accent: ACCENT },
   432|    ui: {
   433|      root: "page",
   434|      elements: {
   435|        page: { type: "stack", props: {}, children: ["title", "sub", "sp", "btns"] },
   436|        title: { type: "text", props: { content: "Pass? or Yass?", size: "lg", weight: "bold", align: "center" } },
   437|        sub: { type: "text", props: { content: "Discover Farcaster profiles", size: "sm", align: "center" } },
   438|        sp: { type: "text", props: { content: " ", size: "sm" } },
   439|        btns: { type: "stack", props: { direction: "horizontal", gap: "md" }, children: ["bp", "by"] },
   440|        bp: {
   441|          type: "button", props: { label: "Pass", variant: "secondary" },
   442|          on: { press: { action: "submit", params: { target: `${base}/gate-pass` } } },
   443|        },
   444|        by: {
   445|          type: "button", props: { label: "Yass", variant: "primary" },
   446|          on: { press: { action: "submit", params: { target: `${base}/gate-yass` } } },
   447|        },
   448|      },
   449|    },
   450|  };
   451|}
   452|
   453|function profilePage(profile: Profile, remaining: number, base: string, poolCount: number) {
   454|  const bioText = profile.bio ? clamp(profile.bio, 100) : "";
   455|  const metaText = `${profile.followers.toLocaleString()} followers`;
   456|  const remText = poolCount > 1
   457|    ? `${poolCount} profiles left`
   458|    : poolCount === 1 ? "Last profile" : `${remaining} swipes left`;
   459|
   460|  const elements: Record<string, any> = {
   461|    page: {
   462|      type: "stack", props: {},
   463|      children: ["pfp", "name", ...(bioText ? ["bio"] : []), "meta", "sep", "rem", "btns"],
